{
  "terms": [
    {
      "term": "TT System",
      "simpleDefinition": "An earthing arrangement where the consumer's earth is connected directly to the ground via a local electrode, rather than using the supplier's cable.",
      "anchor": "A metal rod driven into the soil outside a building.",
      "misconception": "Thinking that TT systems use the supplier's cable sheath for the earth return path."
    },
    {
      "term": "TN-S System",
      "simpleDefinition": "An earthing arrangement where the supplier provides a separate earth conductor (usually the cable sheath) all the way back to the transformer.",
      "anchor": "A dedicated earth terminal provided by the supplier on their incoming cable.",
      "misconception": "Confusing it with TN-C-S; remember the 'S' stands for 'Separate' neutral and earth."
    },
    {
      "term": "TN-C-S System",
      "simpleDefinition": "An earthing arrangement where the neutral and earth are combined in the supplier's cable but separated at the consumer's intake.",
      "anchor": "Commonly known as PME (Protective Multiple Earthing).",
      "misconception": "Believing the earth and neutral remain combined throughout the entire internal installation."
    },
    {
      "term": "ADS (Automatic Disconnection of Supply)",
      "simpleDefinition": "A safety strategy that automatically cuts off power during a fault to prevent electric shock.",
      "anchor": "A circuit breaker 'tripping' or a fuse 'blowing' during a fault.",
      "misconception": "Thinking ADS is a single component; it is actually a system of parts working together."
    },
    {
      "term": "CPC (Circuit Protective Conductor)",
      "simpleDefinition": "The specific wire within a circuit that connects all metal parts of the equipment to the main earthing terminal.",
      "anchor": "The bare copper wire (sleeved green/yellow) inside a standard Twin and Earth cable.",
      "misconception": "Confusing the CPC with the main earthing conductor that connects to the supplier."
    },
    {
      "term": "Earthing Conductor",
      "simpleDefinition": "The main conductor that connects the installation's main earth terminal to the means of earthing (like an electrode or supplier terminal).",
      "anchor": "The thick green and yellow cable connecting the consumer unit to the supplier's earth point.",
      "misconception": "Using the term 'earthing conductor' to describe the small earth wires inside individual light switches."
    },
    {
      "term": "Main Protective Bonding",
      "simpleDefinition": "Conductors used to connect metal services (like water or gas pipes) to the main earthing terminal to keep them at the same voltage.",
      "anchor": "The thick green and yellow wire clamped to the incoming metal water main.",
      "misconception": "Thinking bonding is the same as earthing; bonding is about equalizing voltage between metal parts."
    },
    {
      "term": "Supplementary Bonding",
      "simpleDefinition": "Additional bonding used in high-risk areas, like bathrooms, to connect metal parts together locally.",
      "anchor": "A green and yellow wire connecting a metal radiator to a metal pipe in a shower room.",
      "misconception": "Thinking supplementary bonding is required in every room of a house."
    },
    {
      "term": "Protective Device",
      "simpleDefinition": "A component designed to break the circuit automatically when it detects an overcurrent or fault.",
      "anchor": "A fuse or an MCB (Miniature Circuit Breaker).",
      "misconception": "Believing a protective device only protects against fire; its primary ADS role is protection against shock."
    },
    {
      "term": "Earth Electrode",
      "simpleDefinition": "A conductive part, such as a rod or plate, buried in the ground to provide a physical connection to earth.",
      "anchor": "A copper-clad steel rod driven into the earth for a TT system.",
      "misconception": "Thinking every house needs an earth electrode; they are primarily for TT systems."
    }
  ],
  "anchorPhrases": [
    "TT uses a local earth electrode.",
    "TN-S has a separate earth path.",
    "TN-C-S combines neutral and earth in the supply.",
    "The CPC is the circuit's own earth wire.",
    "The earthing conductor connects the installation to the source earth.",
    "Bonding connects metal services to the earth terminal."
  ],
  "misconceptionTargets": [
    "Confusing the earthing conductor with the CPC.",
    "Thinking TT systems use the supplier's cable for earth.",
    "Believing bonding and earthing are the same thing.",
    "Mixing up the 'S' (Separate) and 'C' (Combined) in TN systems."
  ]
}

{
  "teachChecks": [
    {
      "title": "Earthing System Types",
      "objective": "Identify and distinguish between TT, TN-S, and TN-C-S earthing arrangements.",
      "retrievalTextLines": [
        "Every electrical installation requires a path for fault current to return to the supply transformer to ensure safety. There are three primary earthing arrangements used in the UK. In a TN-S System, the supplier provides a dedicated, separate earth conductor all the way back to the source. This is usually the metallic sheath of the incoming supply cable. The 'S' in the name stands for 'Separate', meaning the neutral and earth conductors are distinct throughout the system.",
        "In a TN-C-S System, the neutral and earth are combined into a single conductor within the supplier's street cables but are separated once they reach the consumer's intake point. This arrangement is commonly known as PME (Protective Multiple Earthing) and is the most frequent setup for modern homes. Finally, a TT System is used when the supplier does not provide an earth connection at all. In this case, the consumer must provide their own connection to the ground, typically by driving a metal earth electrode, such as a copper-clad rod, into the soil."
      ],
      "hint": "Focus on the supplier's connection: TN-S has a separate wire, TN-C-S combines them initially, and TT uses a local rod in the dirt."
    },
    {
      "title": "ADS Component Parts",
      "objective": "Identify the specific components that facilitate Automatic Disconnection of Supply.",
      "retrievalTextLines": [
        "Automatic Disconnection of Supply (ADS) is a safety strategy that uses several components to cut power instantly during a fault. The Circuit Protective Conductor (CPC) is the specific earth wire found within individual circuits, such as the green and yellow sleeved wire in a standard cable. This is different from the earthing conductor, which is the main heavy-gauge cable connecting the entire installation's main earth terminal to the supplier's earth point or a local electrode.",
        "To prevent dangerous voltages on metal services, we use main protective bonding. These are thick conductors clamped to incoming metal water or gas pipes. In specific high-risk areas like bathrooms, supplementary bonding may be used to connect local metal parts together. The 'brain' of the ADS system is the protective device, such as a fuse or MCB (Miniature Circuit Breaker), which detects the fault and trips the power. In TT systems, the earth electrode is the final component that provides the physical connection to the ground."
      ],
      "hint": "The CPC is for circuits, the earthing conductor is the main link to the source, and bonding is for metal pipes."
    }
  ]
}

